const express = require('express');
const csrf = require('csurf');
const session = require('express-session');
const app = express();

// Session middleware
app.use(session({
  secret: 'your-secret-key',
  resave: false,
  saveUninitialized: false,
  cookie: {
    secure: true,
    httpOnly: true,
    sameSite: 'strict'
  }
}));

// CSRF middleware
const csrfProtection = csrf({
  cookie: {
    httpOnly: true,
    secure: true,
    sameSite: 'strict'
  }
});

// Middleware to check authentication
const requireAuth = (req, res, next) => {
  if (!req.session.userId) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  next();
};

// Account deletion endpoint
app.post('/delete-account', requireAuth, csrfProtection, async (req, res) => {
  try {
    const { password } = req.body;
    
    if (!password) {
      return res.status(400).json({ error: 'Password is required' });
    }
    
    // Here you would validate the password against the user's stored password
    // and then delete the account
    const user = await getUserById(req.session.userId);
    
    if (!await validatePassword(password, user.passwordHash)) {
      return res.status(401).json({ error: 'Invalid password' });
    }
    
    await deleteAccount(req.session.userId);
    
    // Clear session
    req.session.destroy();
    
    res.json({ message: 'Account deleted successfully' });
  } catch (error) {
    console.error('Account deletion error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

